package com.example.readermode
/** * Maps structural tokens to their reader-mode word replacements and provides * helpers used by the folding builder and the toggle action. * * Brackets / braces (single-character): * { → tap } → hop * ( → do ) → go * * Subscript brackets (single-character): * [ → at ] → ate * * Argument / list separator (single-character): * , → eft * * Expression terminator (single-character): * ; → ay * * Prefix-negation operator (single-character, prefix connector): * ! → non- (no trailing space; chains as non-non-expr for !!) * * Member-access operators (multi-character): * -> → whose * * Scope-resolution operator (multi-character): * :: → whence * * Variable sigil: * $name → see name * $someVar → see some·var */ object BracketRenderer {
// All single-character structural tokens that get word replacements. // Semicolon is included alongside brackets so the spacing logic // (no trailing space before a token that will add its own leading space) // applies uniformly. private val BRACKET_WORDS = mapOf( '{' to "tap", '}' to "hop", '(' to "do", ')' to "go", '[' to "at", ']' to "ate", ',' to "eft", ';' to "ay", '!' to "non-", )
/** Multi-character structural operators and their reader-mode words. */ private val OPERATOR_WORDS = mapOf( "->" to "whose", "::" to "whence", )
/** * Word used to render the `$` variable sigil. * * "see" is a complete English word (no apocope) with several converging * meanings that all fit the role of a variable sigil: * - **Deictic interjection** — "See!" points at / indicates something, * mirroring the sigil's role of marking a name as a reference to a value. * - **Ecclesiastical noun** — a "see" is the seat where autonomous power * is exercised; by metaphor, the locus at which a value resides and acts * (cf. a memory location). * - Starts with **s**, echoing the struck-S shape of `$` itself. */ const val SIGIL_WORD = "see"
private val WORDS_SET: Set<String> = (BRACKET_WORDS.values + OPERATOR_WORDS.values).toSet()
fun isBracket(c: Char): Boolean = c in BRACKET_WORDS fun wordFor(c: Char): String? = BRACKET_WORDS[c]
fun toWords(text: String): String = text.map { wordFor(it) ?: it.toString() }.joinToString(" ")
fun isOperator(text: String): Boolean = text in OPERATOR_WORDS fun wordForOperator(text: String): String? = OPERATOR_WORDS[text]
/** * Returns true when [c] maps to a prefix-connector word (ends with '-'). * The following token must not add a leading space — the hyphen already * connects them — and [c] itself suppresses its own trailing space. * This makes `!!expr` chain as `non-non-expr` instead of `non- non- expr`. */ fun isConnectingPrefix(c: Char): Boolean = wordFor(c)?.endsWith("-") == true
/** * Returns true when [placeholder] is a reader-mode structural placeholder: * - bracket/operator words ("do", "go", "whose", etc.) * - sigil fold starting with [SIGIL_WORD] * * Used by [ToggleReaderModeAction] to identify which folds belong to us. */ fun isReaderModePlaceholder(placeholder: String): Boolean { val trimmed = placeholder.trim() return when { trimmed == SIGIL_WORD || trimmed.startsWith("$SIGIL_WORD ") -> true else -> trimmed.isNotEmpty() && trimmed.split(' ').filter { it.isNotEmpty() }.all { it in WORDS_SET } } } }

package com.example.readermode
/** * Maps structural tokens to their reader-mode word replacements and provides * helpers used by the folding builder and the toggle action. * * Brackets / braces (single-character): * { → tap } → hop * ( → do ) → go * * Subscript brackets (single-character): * [ → at ] → ate * * Argument / list separator (single-character): * , → eft * * Expression terminator (single-character): * ; → ay * * Prefix-negation operator (single-character, prefix connector): * ! → non- (no trailing space; chains as non-non-expr for !!) * * Member-access operators (multi-character): * -> → whose * * Scope-resolution operator (multi-character): * :: → whence * * Variable sigil (rendered as a connecting prefix): * $name → lo-name * $someVar → lo-some·var * $$name → lo-lo-name (PHP variable variables) */ object BracketRenderer {
// All single-character structural tokens that get word replacements. // Semicolon is included alongside brackets so the spacing logic // (no trailing space before a token that will add its own leading space) // applies uniformly. private val BRACKET_WORDS = mapOf( '{' to "tap", '}' to "hop", '(' to "do", ')' to "go", '[' to "at", ']' to "ate", ',' to "eft", ';' to "ay", '!' to "non-", )
/** Multi-character structural operators and their reader-mode words. */ private val OPERATOR_WORDS = mapOf( "->" to "whose", "::" to "whence", )
/** * Prefix used to render the `$` variable sigil. * * "lo" is a short English interjection meaning "look, here is" — directing * attention to the named thing, exactly as a sigil marks a name as a * reference to a value. The trailing hyphen makes the prefix nature * explicit and connects directly to the identifier: `$variable` → * `lo-variable`. * * For PHP variable variables (`$$name`), the sigils chain naturally: * `$$variable` → `lo-lo-variable`. */ const val SIGIL_PREFIX = "lo-"
private val WORDS_SET: Set<String> = (BRACKET_WORDS.values + OPERATOR_WORDS.values).toSet()
fun isBracket(c: Char): Boolean = c in BRACKET_WORDS fun wordFor(c: Char): String? = BRACKET_WORDS[c]
fun toWords(text: String): String = text.map { wordFor(it) ?: it.toString() }.joinToString(" ")
fun isOperator(text: String): Boolean = text in OPERATOR_WORDS fun wordForOperator(text: String): String? = OPERATOR_WORDS[text]
/** * Returns true when [c] maps to a prefix-connector word (ends with '-'). * The following token must not add a leading space — the hyphen already * connects them — and [c] itself suppresses its own trailing space. * This makes `!!expr` chain as `non-non-expr` instead of `non- non- expr`. */ fun isConnectingPrefix(c: Char): Boolean = wordFor(c)?.endsWith("-") == true
/** * Returns true when [placeholder] is a reader-mode structural placeholder: * - sigil folds: one or more `lo-` prefixes followed by an identifier * - bracket/operator words ("do", "go", "whose", etc.) * * Used by [ToggleReaderModeAction] to identify which folds belong to us. */ fun isReaderModePlaceholder(placeholder: String): Boolean { val trimmed = placeholder.trim() return when { trimmed.matches(Regex("(${Regex.escape(SIGIL_PREFIX)})+\\S+")) -> true else -> trimmed.isNotEmpty() && trimmed.split(' ').filter { it.isNotEmpty() }.all { it in WORDS_SET } } } }

package com.example.readermode

import com.intellij.lang.ASTNode
import com.intellij.lang.folding.FoldingBuilderEx
import com.intellij.lang.folding.FoldingDescriptor
import com.intellij.openapi.editor.Document
import com.intellij.openapi.project.DumbAware
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiRecursiveElementVisitor
import com.intellij.psi.impl.source.tree.LeafPsiElement

/**
 * Folding builder — one fold per token, no merging.
 *
 * Identifiers           → middot placeholder     (quickBrownFox  →  quick·brown·fox)
 * Brackets / braces     → word placeholder       ((  →  do,  {  →  tap)
 * Prefix-negation (!)   → prefix placeholder     (!  →  non-)
 * Member-access (->)    → word placeholder       (->  →  whose)
 * Scope-resolution (::) → word placeholder       (::  →  whence)
 * $ variable sigil      → "see" + name           ($someVar  →  see some·var)
 *
 * Bracket and operator placeholders are padded with spaces so adjacent raw text
 * or other folds are never visually glued:
 *  - leading  space when the preceding source character is not whitespace
 *    AND is not a connecting-prefix token (e.g. !) — so !! chains as non-non-
 *  - trailing space when the following source character is neither whitespace
 *    nor another structural token, AND the word itself does not end with '-'
 *
 * Examples
 *   $obj->makeSomething()
 *     →  [see obj][ whose ][make·something][ do][ go]
 *     =  see obj whose make·something do go
 *
 *   !!$ready
 *     →  [non-][non-][see ready]
 *     =  non-non-see ready
 */
class ReaderModeFoldingBuilder : FoldingBuilderEx(), DumbAware {

    override fun buildFoldRegions(
        root: PsiElement,
        document: Document,
        quick: Boolean,
    ): Array<FoldingDescriptor> {
        if (quick) return emptyArray()

        val source      = document.charsSequence
        val descriptors = mutableListOf<FoldingDescriptor>()

        root.accept(object : PsiRecursiveElementVisitor() {
            override fun visitElement(element: PsiElement) {
                super.visitElement(element)
                if (element !is LeafPsiElement) return
                val text = element.text

                when {
                    // ── Single-character bracket / prefix operator ─────────────
                    text.length == 1 && BracketRenderer.isBracket(text[0]) -> {
                        val word  = BracketRenderer.wordFor(text[0])!!
                        val start = element.textRange.startOffset
                        val end   = element.textRange.endOffset
                        val leading  = if (start > 0
                            && !source[start - 1].isWhitespace()
                            && !BracketRenderer.isConnectingPrefix(source[start - 1])
                        ) " " else ""
                        val trailing = if (end < source.length
                            && !source[end].isWhitespace()
                            && !BracketRenderer.isBracket(source[end])
                            && !word.endsWith("-")
                        ) " " else ""
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, leading + word + trailing)
                        )
                    }

                    // ── Multi-character structural operator (e.g. ->) ─────────
                    BracketRenderer.isOperator(text) -> {
                        val word  = BracketRenderer.wordForOperator(text)!!
                        val start = element.textRange.startOffset
                        val end   = element.textRange.endOffset
                        val leading  = if (start > 0
                            && !source[start - 1].isWhitespace()
                            && !BracketRenderer.isConnectingPrefix(source[start - 1])
                        ) " " else ""
                        val trailing = if (end < source.length
                            && !source[end].isWhitespace()
                            && !BracketRenderer.isBracket(source[end])
                            && !word.endsWith("-")
                        ) " " else ""
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, leading + word + trailing)
                        )
                    }

                    // ── $ variable sigil (e.g. $manager, $someVariable) ───────
                    text.length > 1 && text[0] == '$' -> {
                        val name     = text.substring(1)
                        val nameForm = MiddotConverter.convert(name) ?: name
                        descriptors.add(
                            FoldingDescriptor(
                                element.node, element.textRange, null,
                                "${BracketRenderer.SIGIL_WORD} $nameForm"
                            )
                        )
                    }

                    // ── Compound identifier ────────────────────────────────────
                    text.length >= 2 -> {
                        val middot = MiddotConverter.convert(text) ?: return
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, middot)
                        )
                    }
                }
            }
        })

        return descriptors.toTypedArray()
    }

    override fun getPlaceholderText(node: ASTNode): String {
        val text = node.text
        if (text.length == 1) BracketRenderer.wordFor(text[0])?.let { return it }
        BracketRenderer.wordForOperator(text)?.let { return it }
        if (text.length > 1 && text[0] == '$') {
            val name = text.substring(1)
            return "${BracketRenderer.SIGIL_WORD} ${MiddotConverter.convert(name) ?: name}"
        }
        return MiddotConverter.convert(text) ?: text
    }

    override fun isCollapsedByDefault(node: ASTNode): Boolean =
        ReaderModeService.getInstance().isEnabled
}

package com.example.readermode

import com.intellij.lang.ASTNode
import com.intellij.lang.folding.FoldingBuilderEx
import com.intellij.lang.folding.FoldingDescriptor
import com.intellij.openapi.editor.Document
import com.intellij.openapi.project.DumbAware
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiRecursiveElementVisitor
import com.intellij.psi.impl.source.tree.LeafPsiElement

/**
 * Folding builder — one fold per token, no merging.
 *
 * Identifiers           → middot placeholder     (quickBrownFox  →  quick·brown·fox)
 * Brackets / braces     → word placeholder       ((  →  do,  {  →  tap)
 * Prefix-negation (!)   → prefix placeholder     (!  →  non-)
 * Member-access (->)    → word placeholder       (->  →  whose)
 * Scope-resolution (::) → word placeholder       (::  →  whence)
 * $ variable sigil      → "lo-" prefix           ($someVar  →  lo-some·var, $$v  →  lo-lo-v)
 *
 * Bracket and operator placeholders are padded with spaces so adjacent raw text
 * or other folds are never visually glued:
 *  - leading  space when the preceding source character is not whitespace
 *    AND is not a connecting-prefix token (e.g. !) — so !! chains as non-non-
 *  - trailing space when the following source character is neither whitespace
 *    nor another structural token, AND the word itself does not end with '-'
 *
 * Examples
 *   $obj->makeSomething()
 *     →  [lo-obj][ whose ][make·something][ do][ go]
 *     =  lo-obj whose make·something do go
 *
 *   !!$ready
 *     →  [non-][non-][lo-ready]
 *     =  non-non-lo-ready
 */
class ReaderModeFoldingBuilder : FoldingBuilderEx(), DumbAware {

    override fun buildFoldRegions(
        root: PsiElement,
        document: Document,
        quick: Boolean,
    ): Array<FoldingDescriptor> {
        if (quick) return emptyArray()

        val source      = document.charsSequence
        val descriptors = mutableListOf<FoldingDescriptor>()

        root.accept(object : PsiRecursiveElementVisitor() {
            override fun visitElement(element: PsiElement) {
                super.visitElement(element)
                if (element !is LeafPsiElement) return
                val text = element.text

                when {
                    // ── Single-character bracket / prefix operator ─────────────
                    text.length == 1 && BracketRenderer.isBracket(text[0]) -> {
                        val word  = BracketRenderer.wordFor(text[0])!!
                        val start = element.textRange.startOffset
                        val end   = element.textRange.endOffset
                        val leading  = if (start > 0
                            && !source[start - 1].isWhitespace()
                            && !BracketRenderer.isConnectingPrefix(source[start - 1])
                        ) " " else ""
                        val trailing = if (end < source.length
                            && !source[end].isWhitespace()
                            && !BracketRenderer.isBracket(source[end])
                            && !word.endsWith("-")
                        ) " " else ""
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, leading + word + trailing)
                        )
                    }

                    // ── Multi-character structural operator (e.g. ->) ─────────
                    BracketRenderer.isOperator(text) -> {
                        val word  = BracketRenderer.wordForOperator(text)!!
                        val start = element.textRange.startOffset
                        val end   = element.textRange.endOffset
                        val leading  = if (start > 0
                            && !source[start - 1].isWhitespace()
                            && !BracketRenderer.isConnectingPrefix(source[start - 1])
                        ) " " else ""
                        val trailing = if (end < source.length
                            && !source[end].isWhitespace()
                            && !BracketRenderer.isBracket(source[end])
                            && !word.endsWith("-")
                        ) " " else ""
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, leading + word + trailing)
                        )
                    }

                    // ── $ variable sigil (e.g. $manager, $$someVar) ───────────
                    text.length > 1 && text[0] == '$' -> {
                        val sigils   = text.takeWhile { it == '$' }.length
                        val name     = text.substring(sigils)
                        val nameForm = MiddotConverter.convert(name) ?: name
                        val prefix   = BracketRenderer.SIGIL_PREFIX.repeat(sigils)
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, prefix + nameForm)
                        )
                    }

                    // ── Compound identifier ────────────────────────────────────
                    text.length >= 2 -> {
                        val middot = MiddotConverter.convert(text) ?: return
                        descriptors.add(
                            FoldingDescriptor(element.node, element.textRange, null, middot)
                        )
                    }
                }
            }
        })

        return descriptors.toTypedArray()
    }

    override fun getPlaceholderText(node: ASTNode): String {
        val text = node.text
        if (text.length == 1) BracketRenderer.wordFor(text[0])?.let { return it }
        BracketRenderer.wordForOperator(text)?.let { return it }
        if (text.length > 1 && text[0] == '$') {
            val sigils = text.takeWhile { it == '$' }.length
            val name   = text.substring(sigils)
            return BracketRenderer.SIGIL_PREFIX.repeat(sigils) + (MiddotConverter.convert(name) ?: name)
        }
        return MiddotConverter.convert(text) ?: text
    }

    override fun isCollapsedByDefault(node: ASTNode): Boolean =
        ReaderModeService.getInstance().isEnabled
}

package com.example.readermode

import org.junit.jupiter.api.Assertions.*
import org.junit.jupiter.api.Test
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.CsvSource

class BracketRendererTest {

    @ParameterizedTest(name = "{0} → {1}")
    @CsvSource(
        "{, tap",
        "}, hop",
        "(, do",
        "), go",
        "[, at",
        "], ate",
        "',', eft",
        ";, ay",
        "!, non-",
    )
    fun `maps single brackets to words`(input: String, expected: String) {
        assertEquals(expected, BracketRenderer.wordFor(input[0]))
    }

    @ParameterizedTest(name = "toWords({0}) = {1}")
    @CsvSource(
        "),           go",
        ")),          go go",
        "))),         go go go",
        "(},          do hop",
        "{(,          tap do",
        "))(,         go go do",
    )
    fun `converts bracket sequences to space-joined words`(input: String, expected: String) {
        assertEquals(expected.trim(), BracketRenderer.toWords(input.trim()))
    }

    @ParameterizedTest(name = "{0} → {1}")
    @CsvSource(
        "->, whose",
        "::, whence",
    )
    fun `maps operator tokens to words`(input: String, expected: String) {
        assertEquals(expected, BracketRenderer.wordForOperator(input))
    }

    @ParameterizedTest(name = "sigil rendering: {0} → {1}")
    @CsvSource(
        "\$manager,        see manager",
        "\$someVariable,   see some·variable",
        "\$HTMLParser,     see html·parser",
        "\$this,           see this",
    )
    fun `renders dollar-sigil variables`(rawToken: String, expected: String) {
        val name     = rawToken.removePrefix("$")
        val nameForm = MiddotConverter.convert(name) ?: name
        assertEquals(expected, "${BracketRenderer.SIGIL_WORD} $nameForm")
    }

    @ParameterizedTest(name = "isReaderModePlaceholder({0}) = {1}")
    @CsvSource(
        "go,                true",
        "go go go,          true",
        "do hop,            true",
        "tap,               true",
        "at,                true",
        "ate,               true",
        "eft,               true",
        "ay,                true",
        "whose,             true",
        "whence,            true",
        "non-,              true",
        "see manager,       true",
        "see some·variable, true",
        "see,               true",
        "quick·brown,       false",
        "hello,             false",
        "'',                false",
    )
    fun `identifies reader-mode structural placeholders`(input: String, expected: Boolean) {
        assertEquals(expected, BracketRenderer.isReaderModePlaceholder(input.trim('\'')))
    }

    @Test
    fun `isConnectingPrefix is true only for prefix-connector tokens`() {
        assertTrue(BracketRenderer.isConnectingPrefix('!'))
        assertFalse(BracketRenderer.isConnectingPrefix('('))
        assertFalse(BracketRenderer.isConnectingPrefix(')'))
        assertFalse(BracketRenderer.isConnectingPrefix(';'))
    }
}

package com.example.readermode

import org.junit.jupiter.api.Assertions.*
import org.junit.jupiter.api.Test
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.CsvSource

class BracketRendererTest {

    @ParameterizedTest(name = "{0} → {1}")
    @CsvSource(
        "{, tap",
        "}, hop",
        "(, do",
        "), go",
        "[, at",
        "], ate",
        "',', eft",
        ";, ay",
        "!, non-",
    )
    fun `maps single brackets to words`(input: String, expected: String) {
        assertEquals(expected, BracketRenderer.wordFor(input[0]))
    }

    @ParameterizedTest(name = "toWords({0}) = {1}")
    @CsvSource(
        "),           go",
        ")),          go go",
        "))),         go go go",
        "(},          do hop",
        "{(,          tap do",
        "))(,         go go do",
    )
    fun `converts bracket sequences to space-joined words`(input: String, expected: String) {
        assertEquals(expected.trim(), BracketRenderer.toWords(input.trim()))
    }

    @ParameterizedTest(name = "{0} → {1}")
    @CsvSource(
        "->, whose",
        "::, whence",
    )
    fun `maps operator tokens to words`(input: String, expected: String) {
        assertEquals(expected, BracketRenderer.wordForOperator(input))
    }

    @ParameterizedTest(name = "sigil rendering: {0} → {1}")
    @CsvSource(
        "\$manager,         lo-manager",
        "\$someVariable,    lo-some·variable",
        "\$HTMLParser,      lo-html·parser",
        "\$this,            lo-this",
        "\$\$variable,      lo-lo-variable",
    )
    fun `renders dollar-sigil variables`(rawToken: String, expected: String) {
        val sigils   = rawToken.takeWhile { it == '$' }.length
        val name     = rawToken.substring(sigils)
        val nameForm = MiddotConverter.convert(name) ?: name
        val prefix   = BracketRenderer.SIGIL_PREFIX.repeat(sigils)
        assertEquals(expected.trim(), prefix + nameForm)
    }

    @ParameterizedTest(name = "isReaderModePlaceholder({0}) = {1}")
    @CsvSource(
        "go,                true",
        "go go go,          true",
        "do hop,            true",
        "tap,               true",
        "at,                true",
        "ate,               true",
        "eft,               true",
        "ay,                true",
        "whose,             true",
        "whence,            true",
        "non-,              true",
        "lo-manager,        true",
        "lo-some·variable,  true",
        "lo-lo-variable,    true",
        "quick·brown,       false",
        "hello,             false",
        "'',                false",
    )
    fun `identifies reader-mode structural placeholders`(input: String, expected: Boolean) {
        assertEquals(expected, BracketRenderer.isReaderModePlaceholder(input.trim('\'')))
    }

    @Test
    fun `isConnectingPrefix is true only for prefix-connector tokens`() {
        assertTrue(BracketRenderer.isConnectingPrefix('!'))
        assertFalse(BracketRenderer.isConnectingPrefix('('))
        assertFalse(BracketRenderer.isConnectingPrefix(')'))
        assertFalse(BracketRenderer.isConnectingPrefix(';'))
    }
}
